#include <bits/stdc++.h>
using namespace std;
int n,m,p[500005],s[500005],ans=-5e8;
deque<int> q;
int main(){
    scanf("%d%d",&n,&m);
    s[0]=0;
    q.push_back(0);
    for(int i=1;i<=n;i++)
        scanf("%d",&p[i]);
    for(int i=1;i<=n;i++){
    	s[i]=p[i]+s[i-1];
        ans=max(ans,s[i]-s[q.front()]);
        while(q.size() && q.front()<=i-m)
            q.pop_front();
        while(q.size() && s[q.back()]>=s[i])
            q.pop_back();
        q.push_back(i);
	}
    printf("%d",ans);
    return 0;
}
